func is_special_number(num: Int64): Bool {
    s := string.from_int64(num)
    if s != string.reverse(s) {
        return false
    }

    counts := map[int64]int64{}
    for c in s {
        digit := int64(c - '0')
        counts[digit] += 1
    }

    for digit, count in counts {
        if digit != count {
            return false
        }
    }

    return true
}

func solve(n: Int64): Int64 {
    current := n + 1
    while true {
        if is_special_number(current) {
            return current
        }
        current += 1
    }
